import java.util.List;
import java.util.ArrayList;

public int countValidCombos(List<String> pieces, List<List<Integer>> positions, int index) {
    if (index == pieces.size()) { return 1; }

    int r = positions.get(index).get(0), c = positions.get(index).get(1);
    int[] dr = {0, 1, 0, -1, 1, 1, -1, -1};
    int[] dc = {1, 0, -1, 0, 1, -1, 1, -1};
    int valids = 0;

    for (int x = 0; x < 8; ++x) {
        if (pieces.get(index).equals("bishop") && x < 4) continue;
        if (pieces.get(index).equals("rook") && x >= 4) break;

        for (int dist = 1; dist <= 8; dist++) {
            int nr = r + dr[x] * dist;
            int nc = c + dc[x] * dist;
            if (nr < 1 || nr > 8 || nc < 1 || nc > 8) break;
            if (nr == r && nc == c) continue;

            boolean valid = true;
            for (int other = 0; other < positions.size(); ++other) {
                if (other == index) continue;
                int orr = positions.get(other).get(0), occ = positions.get(other).get(1);
                if (orr == nr && occ == nc) { valid = false; break; }
                if (orr + occ == nr + nc || orr - occ == nr - nc) { valid = false; break; }
                if (orr == nr || occ == nc) { valid = false; break; }
            }

            if (valid) {
                List<Integer> tmp = new ArrayList<>();
                tmp.add(nr);
                tmp.add(nc);
                positions.set(index, tmp);
                valids += countValidCombos(pieces, positions, index + 1);
                positions.set(index, List.of(r, c));
            }
        }
    }

    return valids;
}
